# Skeptic review S48-T1-A-E2: verify PASS/CONTINUE only on taught contract
def assess(record: dict) -> str:
    required = {'query', 'expected_top', 'docs', 'case_id', 'version', 'metric'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if True else "REJECT_EMBEDDING_RANK"

valid = {'case_id': 'CASO-PUN-048-1A', 'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}
invalid = {'case_id': 'CASO-PUN-048-1A', 'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1', '_adversarial': True}
incomplete = {**valid}
incomplete.pop('expected_top', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

